from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from flask_marshmallow import Marshmallow
from flask_login import current_user

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'mysql+pymysql://root:@localhost/flaskcrud'
db = SQLAlchemy(app)
ma = Marshmallow(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(100))
    email = db.Column(db.String(100))
    role = db.Column(db.String(50))
    account_status = db.Column(db.String(50))
    subscription_tier = db.Column(db.String(50))

    def __init__(self, username, email, role, account_status, subscription_tier):
        self.username = username
        self.email = email
        self.role = role
        self.account_status = account_status
        self.subscription_tier = subscription_tier

class UserSchema(ma.Schema):
    class Meta:
        fields = ('id', 'username', 'email', 'role', 'account_status', 'subscription_tier')

user_schema = UserSchema()
users_schema = UserSchema(many=True)

@app.route('/api/users/<id>', methods=['PUT'])
def update_user(id):
    if current_user.role != 'admin':
        return jsonify({'message': 'Not authorized'}), 403

    user = User.query.get(id)

    username = request.json['username']
    email = request.json['email']
    role = request.json['role']
    account_status = request.json['account_status']
    subscription_tier = request.json['subscription_tier']

    user.username = username
    user.email = email
    user.role = role
    user.account_status = account_status
    user.subscription_tier = subscription_tier

    db.session.commit()

    return user_schema.jsonify(user)

